LDR ışık miktarına göre direnç değiştirir:

```cpp
int ldrPin = A0;
int ledPin = 13;
int esikDeger = 500;

void setup() {
  pinMode(ledPin, OUTPUT);
  Serial.begin(9600);
}

void loop() {
  int isikDeger = analogRead(ldrPin);
  Serial.println(isikDeger);

  if (isikDeger < esikDeger) {
    digitalWrite(ledPin, HIGH); // Karanlık → LED yak
  } else {
    digitalWrite(ledPin, LOW);  // Aydınlık → LED söndür
  }
  delay(100);
}
```

